export class CompoundIdField {
    fields;
    constructor(...columns) {
        this.fields = columns;
    }
    apiUpdateAllowed(item) {
        throw new Error('Method not implemented.');
    }
    displayValue(item) {
        throw new Error('Method not implemented.');
    }
    includedInApi;
    toInput(value, inputType) {
        throw new Error('Method not implemented.');
    }
    fromInput(inputValue, inputType) {
        throw new Error('Method not implemented.');
    }
    getDbName() {
        return Promise.resolve('');
    }
    getId(instance) {
        let r = '';
        this.fields.forEach((c) => {
            if (r.length > 0)
                r += ',';
            r += instance[c.key];
        });
        return r;
    }
    options;
    get valueConverter() {
        throw new Error('cant get value converter of compound id');
    }
    target;
    readonly;
    allowNull;
    dbReadOnly;
    isServerExpression;
    key;
    caption;
    inputType;
    dbName;
    valueType;
    isEqualTo(value) {
        let result = {};
        let val = value.toString();
        let id = val.split(',');
        this.fields.forEach((c, i) => {
            result[c.key] = id[i];
        });
        return result;
    }
}
